sql:
SELECT report_id 
FROM income_statement 
WHERE net_income < 1000;

external_knowledge:
- "financial waters" refers to the financial data;
- "average depth of the income stream" refers to the average net income;
- "fiscal seasons" refers to the fiscal periods;
- "financial guardians" refers to the users in the 'Finance' department;
- "sailed the seas of accounting" metaphorically refers to users whose work involves accounting and financial oversight.

sql:
SELECT total_operating_expenses, research_and_development 
FROM operating_expenses 
WHERE report_id = 0;

SELECT ticker, report_date, report_type, fiscal_period, updated_at, status, approval_date
FROM financial_reports
WHERE report_id > 1;

SELECT * 
FROM income_statement 
WHERE sga_expense < (SELECT AVG(sga_expense) FROM income_statement);

SELECT eps_diluted, weighted_average_diluted_shares_outstanding
FROM eps_details
ORDER BY eps_diluted DESC;

SELECT user_name, position
FROM users
WHERE user_id NOT IN (
    SELECT user_id
    FROM access_logs
);

SELECT report_id, ticker, report_date 
FROM financial_reports 
WHERE approved_by = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT net_ppe, goodwill_intangibles
FROM asset_details
WHERE report_id = 0;
